#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""Auto-wire APPROVED discovery sources so they ingest (exit-0-safe). Checks the generic
Socrata collector's state filter, transitions APPROVED->WIRED, runs the collector to pull
rows, reports new business rows + per-source. Completes discover->approve->wire->publish."""
import os,sys,json,time,subprocess
def sh(c,t=100):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "TO/ERR"
def psql(q,t=20):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip() if r.returncode==0 else "ERR:"+r.stderr.strip()[:80])
out={"kind":"wire","ts":int(time.time())}
G="/opt/atlas/importers/atlas_socrata_generic.py"
try:
    out["generic_state_filter"]=sh("grep -nE \"state\\s*(=|IN|==)|WIRED|APPROVED|WHERE|source_catalog|INSERT INTO atlas.business|si\\.|BIZ_INSERT|def main|--loop\" %s 2>/dev/null | head -20"%G)
    out["before_states"]=psql("SELECT state||':'||count(*) FROM atlas.source_catalog GROUP BY state ORDER BY 2 DESC")
    out["wired_count"]=psql("UPDATE atlas.source_catalog SET state='WIRED', last_state_at=now() WHERE state='APPROVED' RETURNING source_key")
    out["after_states"]=psql("SELECT state||':'||count(*) FROM atlas.source_catalog GROUP BY state ORDER BY 2 DESC")
    biz0=psql("SELECT count(*) FROM atlas.business")
    # run the generic collector (bounded)
    out["collector_run"]=sh("cd /opt/atlas && timeout 90 /opt/atlas/venv/bin/python %s 2>&1 | tail -15"%G, t=110)
    biz1=psql("SELECT count(*) FROM atlas.business")
    out["biz_before"]=biz0; out["biz_after"]=biz1
    try: out["new_business_rows"]=int(biz1)-int(biz0)
    except Exception: pass
    out["generic_units"]=sh("systemctl list-timers --all --no-legend 2>/dev/null | grep -iE 'socrata-generic|socrata' | awk '{print $5,$NF}'")
except Exception as e: out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/wire.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"wire","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
